// ❯ @desc Astro build runner. Pagefind removed — search is now powered by /search-index.json.
// ❯ ~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~~

const { execSync } = require('child_process');

// ❯ BUILD EXECUTION
// ❯ @doc Runs Astro build. Search index (/search-index.json) is generated by Astro itself.
function main() {
    try {
        console.log('🔨 Running Astro build...');
        execSync('npx astro build', {
            stdio: 'inherit',
            cwd: process.cwd()
        });
        console.log('✅ Build completed!');
    } catch (error) {
        console.error('❌ Build failed:', error.message);
        process.exit(1);
    }
}

main();
